import{_ as e,a as t,b as n,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o as d,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"WebDAV Kanalı Ekleme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/upload/webdav.md","filePath":"tr-TR/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"tr-TR/upload/webdav.md"};function u(k,a,p,m,y,c){return d(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="webdav-kanalı-ekleme" tabindex="-1">WebDAV Kanalı Ekleme <a class="header-anchor" href="#webdav-kanalı-ekleme" aria-label="Permalink to &quot;WebDAV Kanalı Ekleme&quot;">​</a></h1><h2 id="ne-zaman-uygun" tabindex="-1">Ne Zaman Uygun? <a class="header-anchor" href="#ne-zaman-uygun" aria-label="Permalink to &quot;Ne Zaman Uygun?&quot;">​</a></h2><p>WebDAV kanalını şu durumlarda kullanın:</p><ul><li>WebDAV endpoint sunan bir NAS, bulut disk veya nesne depolama hizmetiniz varsa.</li><li>Yüklenen görsellerin kendi WebDAV dizininizde saklanmasını istiyorsanız.</li><li>Kimlik bilgilerinin uzun süre frontend&#39;de açık kalması yerine D1 <code>upload_channels</code> tablosunda saklanmasını istiyorsanız.</li></ul><h2 id="baslamadan-once-gerekenler" tabindex="-1">Başlamadan Önce Gerekenler <a class="header-anchor" href="#baslamadan-once-gerekenler" aria-label="Permalink to &quot;Başlamadan Önce Gerekenler&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gereken</th><th>Ne için kullanılır</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Sunucu tarafı WebDAV URL&#39;si, örneğin <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>WebDAV hizmetine giriş için kullanıcı adı.</td></tr><tr><td>Password</td><td>WebDAV hizmetine giriş için parola.</td></tr><tr><td>Authentication mode</td><td>Varsayılan <code>Basic</code>. <code>Digest</code> veya otomatik anlaşmayı yalnızca sunucu gerektiriyorsa kullanın.</td></tr><tr><td>Storage directory</td><td>Dosyaların saklanacağı dizin. Varsayılan <code>imgbed</code>.</td></tr></tbody></table><h2 id="nereden-eklenir" tabindex="-1">Nereden Eklenir? <a class="header-anchor" href="#nereden-eklenir" aria-label="Permalink to &quot;Nereden Eklenir?&quot;">​</a></h2><ol><li>Sistem Ayarları&#39;nı açın.</li><li>Yükleme Ayarları&#39;na gidin.</li><li>Sağ üst köşedeki Add Channel düğmesine tıklayın.</li><li><code>WebDAV</code> seçeneğini seçin.</li></ol><h2 id="alan-acıklamaları" tabindex="-1">Alan Açıklamaları <a class="header-anchor" href="#alan-acıklamaları" aria-label="Permalink to &quot;Alan Açıklamaları&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Alan</th><th>Ne işe yarar</th><th>Zorunlu</th></tr></thead><tbody><tr><td>Kanal adı</td><td>Bu WebDAV kanalı için anlaşılır bir ad, örneğin <code>koofr</code> veya <code>nas</code>.</td><td>Evet</td></tr><tr><td>Endpoint</td><td><code>https://</code> dahil tam WebDAV endpoint adresi.</td><td>Evet</td></tr><tr><td>Username</td><td>WebDAV giriş kullanıcı adı.</td><td>Evet</td></tr><tr><td>Password</td><td>WebDAV giriş parolası.</td><td>Evet</td></tr><tr><td>Authentication mode</td><td>Genellikle <code>Basic</code>; sunucu digest authentication istiyorsa <code>Digest</code> kullanın.</td><td>Evet</td></tr><tr><td>Storage directory</td><td>Dosyaların saklandığı dizin. Varsayılan <code>imgbed</code>.</td><td>Hayır</td></tr></tbody></table><h2 id="ornek-fie-nl-tab-digital" tabindex="-1">Örnek: fie.nl.tab.digital <a class="header-anchor" href="#ornek-fie-nl-tab-digital" aria-label="Permalink to &quot;Örnek: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-olusturun" tabindex="-1">1. App Password Oluşturun <a class="header-anchor" href="#_1-app-password-olusturun" aria-label="Permalink to &quot;1. App Password Oluşturun&quot;">​</a></h3><p>Hesap güvenliği ayarlarınızı açın, application passwords bölümünü bulun ve yeni bir app password oluşturun.</p><p><img src="'+e+'" alt="App password oluşturma" loading="lazy"></p><p>Oluşturulduktan sonra yeni app password değerini kopyalayıp kaydedin. Genellikle yalnızca bir kez gösterilir.</p><p><img src="'+t+'" alt="Yeni app password değerini kaydetme" loading="lazy"></p><h3 id="_2-imgbed-de-webdav-yapılandırmasını-doldurun" tabindex="-1">2. ImgBed&#39;de WebDAV Yapılandırmasını Doldurun <a class="header-anchor" href="#_2-imgbed-de-webdav-yapılandırmasını-doldurun" aria-label="Permalink to &quot;2. ImgBed&#39;de WebDAV Yapılandırmasını Doldurun&quot;">​</a></h3><p>ImgBed&#39;e dönün ve bir WebDAV kanalı ekleyin:</p><table tabindex="0"><thead><tr><th>Arayüz Alanı</th><th>Değer</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> tarafından verilen WebDAV URL&#39;si.</td></tr><tr><td>Username</td><td>WebDAV kullanıcı adınız.</td></tr><tr><td>Password</td><td>Az önce oluşturduğunuz app password.</td></tr><tr><td>Authentication mode</td><td>Çoğu durumda <code>Basic</code> ile başlayın.</td></tr><tr><td>Storage directory</td><td>Varsayılan <code>imgbed</code>; isterseniz özel bir dizin kullanabilirsiniz.</td></tr></tbody></table><p><img src="'+n+'" alt="Yapılandırmayı doldurma" loading="lazy"></p><h2 id="buyuk-dosya-yukleme-davranısı" tabindex="-1">Büyük Dosya Yükleme Davranışı <a class="header-anchor" href="#buyuk-dosya-yukleme-davranısı" aria-label="Permalink to &quot;Büyük Dosya Yükleme Davranışı&quot;">​</a></h2><p>WebDAV kanalı gerçek, oturum tabanlı parçalı yükleme kullanır.</p><p>Küçük dosyalar tek parça dosya olarak yüklenir. 64 MiB&#39;den büyük dosyalar otomatik olarak yaklaşık 10 MiB&#39;lik parçalara bölünür ve uzaktaki parça dizinine yüklenir.</p><p>WebDAV hizmetinin <code>partial update</code> veya offset tabanlı yazmayı desteklemesi gerekmez. ImgBed parçaları uzak sunucuda tek büyük dosyada birleştirmez. Bunun yerine parça manifest&#39;ini saklar ve dosya istendiğinde parçaları sırayla okur.</p><p>Pratikte:</p><table tabindex="0"><thead><tr><th>Dosya Boyutu</th><th>Yükleme Yöntemi</th><th>Uzak Depolama Yapısı</th></tr></thead><tbody><tr><td>64 MiB veya daha küçük</td><td>Normal yükleme</td><td>Tek tam dosya</td></tr><tr><td>64 MiB&#39;den büyük</td><td>Gerçek session chunked upload</td><td>Birden çok parça dosyası içeren parça dizini</td></tr></tbody></table><p>Parça dizini yalnızca uzak depolama düzenini etkiler. ImgBed&#39;deki dosya URL&#39;sini değiştirmez. Kullanıcılar dosyaya yine özgün <code>/file/...</code> bağlantısı üzerinden erişir.</p><h2 id="kurulum-adımları" tabindex="-1">Kurulum Adımları <a class="header-anchor" href="#kurulum-adımları" aria-label="Permalink to &quot;Kurulum Adımları&quot;">​</a></h2><ol><li>Yükleme Ayarları&#39;nı açın.</li><li>Add Channel düğmesine tıklayın.</li><li><code>WebDAV</code> seçeneğini seçin.</li><li>Tanıyabileceğiniz bir kanal adı girin, örneğin <code>koofr</code>.</li><li>WebDAV endpoint adresini girin, örneğin <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Username ve password değerlerini girin.</li><li>Varsayılan olarak authentication mode değerini <code>Basic</code> bırakın.</li><li>Storage directory değerini <code>imgbed</code> bırakın veya kendi dizininizle değiştirin.</li><li>Save düğmesine tıklayın.</li><li>Kaydettikten sonra kanal kartını kontrol edin, mümkünse kapasite sorgulayın ve test dosyası yükleyin.</li></ol><h2 id="nasıl-kontrol-edilir" tabindex="-1">Nasıl Kontrol Edilir? <a class="header-anchor" href="#nasıl-kontrol-edilir" aria-label="Permalink to &quot;Nasıl Kontrol Edilir?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrol</th><th>Nasıl doğrulanır</th></tr></thead><tbody><tr><td>Kanal kartı görünür</td><td>Kaydettikten sonra Yükleme Ayarları sayfasında WebDAV kanal kartı görünmelidir.</td></tr><tr><td>Kanal etkindir</td><td>Kartın sağ üst köşesindeki anahtar açık kalmalıdır.</td></tr><tr><td>Kimlik bilgileri kaydedilmiştir</td><td>Ayrıntı görünümünde Endpoint, username, authentication mode ve storage directory görünmelidir.</td></tr><tr><td>Küçük dosya yüklenir</td><td>Test görseli yükleyin ve dosyanın WebDAV dizininde göründüğünü doğrulayın.</td></tr><tr><td>Büyük dosya kuralı çalışır</td><td>64 MiB&#39;den büyük dosyalar chunked upload kullanır ve uzakta parça dizini oluşturur.</td></tr><tr><td>Kapasite sorgusu çalışır</td><td>Sunucu kapasite bilgisini destekliyorsa sorgu kullanılan ve toplam kapasiteyi gösterir.</td></tr></tbody></table><p><img src="'+i+`" alt="Kota sorgusu başarılı" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="buyuk-webdav-dosyaları-neden-parca-dizini-olusturuyor" tabindex="-1">Büyük WebDAV dosyaları neden parça dizini oluşturuyor? <a class="header-anchor" href="#buyuk-webdav-dosyaları-neden-parca-dizini-olusturuyor" aria-label="Permalink to &quot;Büyük WebDAV dosyaları neden parça dizini oluşturuyor?&quot;">​</a></h3><p>Büyük dosyalar için geçerli depolama yöntemi budur.</p><p>64 MiB&#39;den büyük dosyalar tek büyük uzak dosyada birleştirilmez. Parça dizini olarak saklanır. ImgBed parça manifest&#39;ini kaydeder ve tam içeriği parçaları sırayla okuyarak döndürür.</p><h3 id="buyuk-dosya-yuklemesi-basarısız-olursa-once-neyi-kontrol-etmeliyim" tabindex="-1">Büyük dosya yüklemesi başarısız olursa önce neyi kontrol etmeliyim? <a class="header-anchor" href="#buyuk-dosya-yuklemesi-basarısız-olursa-once-neyi-kontrol-etmeliyim" aria-label="Permalink to &quot;Büyük dosya yüklemesi başarısız olursa önce neyi kontrol etmeliyim?&quot;">​</a></h3><p>Önce Endpoint, username, password ve storage directory değerlerini kontrol edin. Sonra WebDAV hizmetinin dizin oluşturma, dosya yazma ve dosya okuma işlemlerine izin verdiğini doğrulayın.</p><p>Kapasite sorgusu başarısız olsa ama küçük dosya yükleme çalışsa, sunucu kapasite raporlamasını desteklemiyor veya kısıtlıyor olabilir. Bu durum yüklemenin kullanılamaz olduğu anlamına gelmez.</p><h3 id="hangi-authentication-mode-kullanılmalı" tabindex="-1">Hangi authentication mode kullanılmalı? <a class="header-anchor" href="#hangi-authentication-mode-kullanılmalı" aria-label="Permalink to &quot;Hangi authentication mode kullanılmalı?&quot;">​</a></h3><p><code>Basic</code> ile başlayın.</p><p>Sunucu açıkça digest authentication istiyorsa <code>Digest</code> kullanın.</p><p>Emin değilseniz otomatik anlaşmayı kullanın.</p><h2 id="kısa-kontrol-listesi" tabindex="-1">Kısa Kontrol Listesi <a class="header-anchor" href="#kısa-kontrol-listesi" aria-label="Permalink to &quot;Kısa Kontrol Listesi&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username ve password hazırla</span></span>
<span class="line"><span>-&gt; Yükleme Ayarları&#39;nı aç</span></span>
<span class="line"><span>-&gt; Kanal ekle</span></span>
<span class="line"><span>-&gt; WebDAV seç</span></span>
<span class="line"><span>-&gt; Endpoint / username / password gir</span></span>
<span class="line"><span>-&gt; Varsayılan olarak authentication mode değerini Basic bırak</span></span>
<span class="line"><span>-&gt; Varsayılan olarak storage directory değerini imgbed bırak</span></span>
<span class="line"><span>-&gt; Kaydet</span></span>
<span class="line"><span>-&gt; Kapasite sorgula</span></span>
<span class="line"><span>-&gt; Test dosyası yükle</span></span></code></pre></div>`,45)])])}const z=r(s,[["render",u]]);export{g as __pageData,z as default};
